import React, { useRef, useCallback, useState, useEffect } from 'react';
import './styles.css'
import ProgressBar from './ProgressBar'
import { useProgressStore } from './useProgressStore';

function ProgressBars() {
    const { bars, addBar, progressQueue } = useProgressStore((state) => state)

    const queueRef = useRef([]);
    const currentRef = useRef(null); // 🔥 current active id
    console.log('queueRefoutside', queueRef.current)

    console.log('currentRef', currentRef)
    function startNext() {
        if (currentRef.current !== null) return;

        const nextId = queueRef.current.shift();
        if (!nextId) return;

        currentRef.current = nextId;

        setBars((prev) =>
            prev.map((b) =>
                b.id === nextId ? { ...b, active: true } : b
            )
        );
    }

    // function addBar() {
    //     const id = crypto.randomUUID();

    //     setBars((prev) => [...prev, { id, active: false }]);

    //     queueRef.current.push(id);
    //     console.log('queueRef', queueRef.current)

    //     // 🔥 start immediately if idle
    //     startNext();
    // }
    useEffect(() => {

    }, [progressQueue])

    function handleComplete(id) {
        if (currentRef.current === id) {
            currentRef.current = null;
        }

        setBars((prev) =>
            prev.map((b) =>
                b.id === id ? { ...b, active: false } : b
            )
        );

        // 🔥 trigger next synchronously
        startNext();
    }

    return (
        <>
            <div>
                {bars.map((bar, idx) => (
                    <ProgressBar key={bar.id}
                        active={bar.active}
                        duration={1000}
                        onComplete={() => handleComplete(bar.id)} />
                ))}
            </div>
            <button onClick={addBar}>+Add</button>
        </>
    )
}

export default ProgressBars
